List reportees = new ArrayList();
int rDays  = 30;		
  String manager = "10174665";
  String accountExpire = "accountExpires";
  IdentityUtils iu = new IdentityUtils();
  public static long daysBetween(String expDate) {
		LocalDate nowDate = LocalDate.now();
		DateTimeFormatter formatter = DateTimeFormatter.ofPattern("MM/dd/yyyy");
		LocalDate dateTime = null;
		long daysBetween = 0;
		if(expDate != null) {
				dateTime = LocalDate.parse(expDate, formatter);
				daysBetween = ChronoUnit.DAYS.between(nowDate, dateTime);
		}
		return daysBetween;
	}
  
  
  public static boolean checkADExpDateMatch(String expDate, int rDays) {
		boolean readyForExpiration = false;
		Object adExpDateValueObj = expDate;
		if (null != adExpDateValueObj) {
			if (adExpDateValueObj instanceof String) {
				if (!adExpDateValueObj.toString().equalsIgnoreCase("never") || !Util.isNullOrEmpty(accountExpire)) {
					long diff = daysBetween(adExpDateValueObj.toString());
					if (diff <= rDays) {
						readyForExpiration = true;
					}
				}
			}
			if (adExpDateValueObj instanceof Date) {
				long diff = daysBetween((Date) adExpDateValueObj);
				if (diff <= rDays) {
					readyForExpiration = true;
				}
			}
		}
		return readyForExpiration;
	}
  
public List getFilteredADLinksForManager(String managerName,int expiringInDays) throws GeneralException, ParseException{
		List idList = new ArrayList();
		try {
		  QueryOptions qo = new QueryOptions();
		  List idType = new ArrayList();
		  idType.add("contractor");
		  idType.add("non-hr contractor");
	   	Filter f = Filter.ignoreCase(Filter.and(Filter.eq("manager.name", managerName),Filter.eq("inactive", false),Filter.in("type",idType)));
		qo.addFilter(f);
		Iterator iterator = context.search(Identity.class, qo);
		while (iterator.hasNext()) {
			Identity idn = (Identity) iterator.next();
      
			if (null != idn @and !idn.isInactive()) {
				String displayName = idn.getDisplayableName().replaceAll(",", "");
				String manager = idn.getManager() != null ? idn.getManager().getDisplayableName().replaceAll(",", "").toString() : null;
				String idName = idn.getName();
				String idEmail = idn.getEmail() != null ? idn.getEmail().toString() : "Not Available";
				String firstName =  idn.getFirstname() != null ? idn.getFirstname().toString() : "Not Available";
				String lastName =  idn.getLastname() != null ? idn.getLastname().toString() : "Not Available";
        String idnType = idn.getType() != null ? StringUtils.capitalize(idn.getType().toString()) : "Not Available";
				String contractorManager = idn.getAttribute("contractorManager") != null ? idn.getAttribute("contractorManager").toString() : null;
				String cmDisplayName = "Not Available";
				String cmExternalEmail = "Not Available";
				if(null != contractorManager){
					Identity cmIdn = context.getObjectByName(Identity.class,contractorManager);
					cmDisplayName = cmIdn.getDisplayableName() != null ? cmIdn.getDisplayableName().toString().replaceAll(",", "") : "Not Available";
					cmExternalEmail = cmIdn.getAttribute("externalEmail") != null ? cmIdn.getAttribute("externalEmail").toString() : "Not Available"; 
				}
				List links = iu.getIdFilteredActiveADLinks(idn);
	        for(Link link : links){
					Date today = new Date();
					String expirationDate = null;
            boolean containsRec = false;
	        
          Object expDateObj = link.getAttribute(accountExpire);
					List expDateOptions = new ArrayList();
					expDateOptions.add("never");
					expDateOptions.add("");
					if (!Util.nullSafeContains(expDateOptions, expDateObj)) {
						Date futureAccExpiration = null;
						try{
							futureAccExpiration = Util.stringToDate(expDateObj.toString());
							expirationDate = Util.dateToString(futureAccExpiration,"MM/dd/yyyy");
						}catch(java.text.ParseException pe){
							log.error("Date Conversion Error: ",pe);
						}
					}
					containsRec = checkADExpDateMatch(expirationDate,expiringInDays);
					String accountNameString = link.getDisplayName() != null ? link.getDisplayName().toString() : null;
					String domainName = null;
					String accountName = null;
					if(null != accountNameString){
						domainName = accountNameString.split("\\\\")[0];
						accountName = link.getAttribute("sAMAccountName");
					}
	                idAttribList = new ArrayList();
	                if(containsRec @and idAttribList.isEmpty()) {
					
                  String reportData = idnType+","+displayName+","+idName+","+firstName+","+lastName+","+idEmail+","+manager+","+cmDisplayName+","+cmExternalEmail+","+domainName+","+accountName+","+expirationDate;
                  idList.add(reportData);
                }
	           }
	          }			
			
				}
		}catch(Exception e) {
			log.error("ERROR: In getFilteredADLinksForManager: ",e );
      throw new RuntimeException("ERROR: In getFilteredADLinksForManager: ",e);
		}
    return idList.stream().distinct().collect(Collectors.toList());
	 }
	 
	 public List getManagers(){
		List outIdn = new ArrayList();
	  QueryOptions qo = new QueryOptions();
		 Filter f = Filter.ignoreCase(Filter.and(Filter.eq("managerStatus", true),Filter.eq("inactive", false), Filter.eq("correlated",true), Filter.eq("name","10174522")));
     //Filter f = Filter.ignoreCase(Filter.and(Filter.eq("managerStatus", true),Filter.eq("inactive", false), Filter.eq("correlated",true)));
		 qo.addFilter(f);
		 Iterator iterator = context.search(Identity.class, qo);
		 while (iterator.hasNext()) {
      Identity idn = (Identity) iterator.next();
			outIdn.add(idn);
		}
     return outIdn;
	 }
public boolean sendEmail(Map finalDataMap, String toAddress){
	String finalRecords = null;
	Map mailargs = new HashMap();
    String strTemplate = "Ascension-EmailTemplate-CWR-AccountExpirationEmail";
    String fileName = "account_expiration_data.csv";
    EmailTemplate template = context.getObjectByName(EmailTemplate.class, strTemplate);
    EmailOptions mailopts = null;
    EmailFileAttachment attachment = null;
	dataBuilder = new StringBuilder();
	dataBuilder.append("\"Index\",\"User Type\",\"User DisplayName\",\"User Name\",\"First Name\",\"Last Name\",\"User Email \",\"Manager Name\",\"Contractor Manager Name\",\"Contractor Manager Email\",\"Domain Name\",\"Account ID\",\"Expiration Date\"\n");
	  List records  = finalDataMap.get("dataList");
    int i = 0;
	  for (String rec: records) {
        dataBuilder.append(i.toString());
        dataBuilder.append(",");
        dataBuilder.append(rec);
        dataBuilder.append("\n");
        i++;
    }
    finalRecords = dataBuilder.toString().replaceAll("null", "");
		mailopts = new EmailOptions(toAddress, mailargs);
    attachment = new EmailFileAttachment(fileName, EmailFileAttachment.MimeType.MIME_CSV, finalRecords.getBytes("UTF-8"));
    mailopts.addAttachment(attachment);
    context.sendEmailNotification(template, mailopts);
  return true;
}
Map finalData;
List managerList = getManagers();
 
if(null != managerList @and !managerList.isEmpty()){
	for(Identity i : managerList){
		String managerEmail = i.getEmail() != null ? i.getEmail().toString() : null;
    String externalEmail = i.getAttribute("externalEmail") != null ? i.getAttribute("externalEmail").toString() : null;
		String toAddresss = null;
		if(null != managerEmail){toAddress = managerEmail;}
		else if(null != externalEmail @and null != toAddress){ toAddress = toAddress+","+externalEmail;}
		else if(null != externalEmail @and null == toAddress){toAddress = externalEmail;}
		if(null != toAddress ){
      List listOfReportees = getFilteredADLinksForManager(i.getName(),rDays);
      if(null != listOfReportees){
        finalData = new HashMap();
				finalData.put("dataList",listOfReportees);
        //sendEmail(finalData,toAddress);
        
		  }
		}
	}	 
}
